import { useState } from "react";

const SAMPLE = `NOTIFICATION FOR INSPECTION
PROJECT No. 1000482 – MERAM PROJECT
Notification No. 148A, Rev A
Vendor / Subcontractor Name: Siemens Energy LLC
Place of Witness / Manufacturer & Factory:
Innomotics sro, Electric Machines Factory, Drasov, Czech Republic
Address Čedlosy 126, 664 24 Drasov
Date of Inspection 09.07.2024
Time 07:30 am CET
ITP Step No F47
Inspection Activity Partial-discharge measurement`;

export default function Home() {
  const [text, setText] = useState("");
  const [fileName, setFileName] = useState("");
  const [selectedFile, setSelectedFile] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [status, setStatus] = useState("Ready.");

  function onFile(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setSelectedFile(file);
    setFileName(file.name);
    setResult(null);
    setError("");
    setStatus("File selected. Click Analyse document.");
  }

  async function analyseCurrentInput() {
    setLoading(true);
    setError("");
    try {
      if (selectedFile) {
        setStatus("Uploading and analysing file...");
        const form = new FormData();
        form.append("file", selectedFile);
        const res = await fetch(process.env.NEXT_PUBLIC_BACKEND_URL + "/analyse/file", { method:"POST", body: form });
        const data = await res.json();
        if (!res.ok) throw new Error(data.detail || "File analysis failed.");
        setResult(data);
        setStatus("File analysed successfully.");
        return;
      }

      if (text.trim()) {
        setStatus("Analysing pasted text...");
        const form = new FormData();
        form.append("text", text);
        form.append("file_name", fileName);
        const res = await fetch(process.env.NEXT_PUBLIC_BACKEND_URL + "/analyse/text", { method:"POST", body: form });
        const data = await res.json();
        if (!res.ok) throw new Error(data.detail || "Text analysis failed.");
        setResult(data);
        setStatus("Text analysed successfully.");
        return;
      }

      throw new Error("Choose a file or paste document text first.");
    } catch (err) {
      setError(err.message || "Analysis failed.");
      setStatus("Analysis failed.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="page">
      <section className="hero">
        <div className="brand">
          <img src="data:image/jpeg;base64," alt="Vinqu logo" className="logo" />
          <div>
            <h1>Vinqu</h1>
            <p className="tag">From Evidence to Insight</p>
          </div>
        </div>
        <p className="sub">Upload PDF, DOCX, TXT, or XLSX inspection documents. Vinqu classifies the document, extracts key fields, and generates a pre-inspection briefing.</p>
      </section>

      <section className="grid">
        <div className="card">
          <h2>Document input</h2>
          <label>Upload file</label>
          <input type="file" onChange={onFile} accept=".pdf,.docx,.txt,.md,.csv,.log,.xlsx" />
          <label>File name / reference</label>
          <input value={fileName} onChange={e => setFileName(e.target.value)} />
          <label>Document text</label>
          <textarea value={text} onChange={e => setText(e.target.value)} placeholder="Paste document text here if you are not uploading a file." />
          <div className="actions">
            <button className="ghost" onClick={() => { setText(SAMPLE); setFileName("sample-noi.txt"); setSelectedFile(null); setResult(null); setError(""); setStatus("Sample loaded."); }}>Load sample</button>
            <button onClick={analyseCurrentInput} disabled={loading}>{loading ? "Analysing..." : "Analyse document"}</button>
          </div>
          <p className="status">{status}</p>
          {error ? <p className="error">{error}</p> : null}
        </div>

        <div className="card">
          <h2>Analysis result</h2>
          {!result ? <p className="muted">No result yet.</p> : (
            <>
              <div className="resultGrid">
                <Info title="Document type" value={result.document_type} />
                <Info title="Nature of work" value={result.nature_of_work} />
                <Info title="Project / reference" value={result.project_reference || result.project_name || "-"} />
                <Info title="Location" value={result.inspection_factory_location || result.site_of_inspection || "-"} />
                <Info title="Equipment / scope" value={result.equipment_scope || "-"} />
                <Info title="Confidence" value={result.confidence_level || "-"} />
              </div>
              <Block title="Reasoned summary"><p>{result.reasoned_summary}</p></Block>
              <div className="twoCols">
                <List title="Standards" items={result.applicable_standards} />
                <List title="Tests / checks" items={result.tests_or_checks} />
                <List title="Contacts" items={result.named_contacts} />
                <List title="Missing / uncertain" items={result.missing_information} />
              </div>
            </>
          )}
        </div>
      </section>
    </main>
  );
}

function Info({ title, value }) {
  return <div className="info"><div className="t">{title}</div><div className="v">{value || "-"}</div></div>;
}

function Block({ title, children }) {
  return <div className="block"><h3>{title}</h3>{children}</div>;
}

function List({ title, items = [] }) {
  return <Block title={title}>{items.length ? <ul>{items.map((item, i) => <li key={i}>{item}</li>)}</ul> : <p className="muted">None</p>}</Block>;
}
